#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

typedef struct {
    int *data;
    int front, rear, size, capacity;
} Queue;

Queue* createQueue(int capacity) {
    Queue *q = (Queue*)malloc(sizeof(Queue));
    q->data = (int*)malloc(capacity * sizeof(int));
    q->front = 0;
    q->rear = -1;
    q->size = 0;
    q->capacity = capacity;
    return q;
}

void enqueue(Queue *q, int x) {
    q->rear = (q->rear + 1) % q->capacity;
    q->data[q->rear] = x;
    q->size++;
}

int dequeue(Queue *q) {
    int x = q->data[q->front];
    q->front = (q->front + 1) % q->capacity;
    q->size--;
    return x;
}

int isEmpty(Queue *q) { return q->size == 0; }

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        int *adjSize = (int*)calloc(N + 1, sizeof(int));
        int **adj = (int**)malloc((N + 1) * sizeof(int*));
        for (int i = 1; i <= N; ++i) adj[i] = (int*)malloc((M + 1) * sizeof(int));
        for (int i = 0; i < M; ++i) {
            int a, b; scanf("%d %d", &a, &b);
            adj[a][adjSize[a]++] = b;
            adj[b][adjSize[b]++] = a;
        }
        int *dist = (int*)malloc((N + 1) * sizeof(int));
        for (int i = 1; i <= N; ++i) dist[i] = INT_MAX;
        Queue *q = createQueue(N + 5);
        enqueue(q, 1);
        dist[1] = 0;
        while (!isEmpty(q)) {
            int v = dequeue(q);
            if (v == N) break;
            for (int i = 0; i < adjSize[v]; ++i) {
                int nb = adj[v][i];
                if (dist[v] + 1 < dist[nb]) {
                    dist[nb] = dist[v] + 1;
                    enqueue(q, nb);
                }
            }
        }
        if (dist[N] == INT_MAX) printf("-1\n");
        else printf("%d\n", dist[N] + 1);
        for (int i = 1; i <= N; ++i) free(adj[i]);
        free(adj);
        free(adjSize);
        free(dist);
        free(q->data);
        free(q);
    }
    return 0;
}

