const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(input[idx++], 10);
let results = [];
for (let t = 0; t < T; t++) {
  const [Nstr, Mstr] = input[idx++].trim().split(/\s+/);
  const N = parseInt(Nstr, 10);
  const M = parseInt(Mstr, 10);
  const graph = Array.from({ length: N + 1 }, () => []);
  for (let i = 0; i < M; i++) {
    const [aStr, bStr] = input[idx++].trim().split(/\s+/);
    const a = parseInt(aStr, 10);
    const b = parseInt(bStr, 10);
    graph[a].push(b);
    graph[b].push(a);
  }
  const dist = new Array(N + 1).fill(Infinity);
  const queue = [];
  let head = 0;
  queue.push(1);
  dist[1] = 0;
  while (head < queue.length) {
    const v = queue[head++];
    if (v === N) break;
    for (const nb of graph[v]) {
      if (dist[v] + 1 < dist[nb]) {
        dist[nb] = dist[v] + 1;
        queue.push(nb);
      }
    }
  }
  results.push(dist[N] === Infinity ? '-1' : String(dist[N] + 1));
}
console.log(results.join('\n'));
